css:
.loader {
  position: relative;
  display: inline-block;
  width: 58px;
  height: 58px;
  border: 2px solid rgba(99, 102, 241, 0.22);
  border-radius: 50%;
}
.loader::before {
  content: "";
  position: absolute;
  inset: 9px 25px;
  border-radius: 999px;
  background: #6366f1;
  transform-origin: 50% 20px;
  animation: spin 1s cubic-bezier(.6,.2,.4,.8) infinite;
}
.loader::after {
  content: "";
  position: absolute;
  inset: 24px;
  border-radius: 50%;
  background: #6366f1;
}
@keyframes spin { to { transform: rotate(360deg); } }
